const e=[{date:"2026-05-16",items:["Gels de s\xE9rie : l'enfant gagne automatiquement un gel (\u2744\uFE0F) tous les 7 jours d'affil\xE9e (2 max en r\xE9serve). Quand il manque un jour, le gel sauve la s\xE9rie en silence \xE0 la s\xE9ance suivante \u2014 le r\xE9cap c\xE9l\xE8bre l'\xE9v\xE9nement. Plus de gros z\xE9ro apr\xE8s une seule journ\xE9e d'absence."]},{date:"2026-05-13",items:["Nouvelle r\xE8gle bonus \xAB \xD711 \xBB dans l'\xE9cran R\xE8gles : quand toutes les tables de 2 \xE0 9 sont ma\xEEtris\xE9es, l'enfant d\xE9couvre l'astuce \xAB il suffit de r\xE9p\xE9ter le chiffre \xBB (3\xD711 = 33, 7\xD711 = 77\u2026). Pastille \xAB Nouveau \xBB discr\xE8te sur le bouton R\xE8gles le jour du d\xE9blocage."]},{date:"2026-05-08",items:["Les deux derniers faits (8\xD79 et 9\xD79) ne sont plus bloqu\xE9s par un planning de r\xE9vision charg\xE9 : un slot leur est d\xE9sormais r\xE9serv\xE9 en fin de parcours, m\xEAme quand 15+ r\xE9visions sont dues le m\xEAme jour.","Reconnaissance vocale plus fluide en s\xE9ance : le micro reste actif toute la s\xE9ance (moins de bips iOS)."]},{date:"2026-05-06",items:["Deux nouveaux badges interm\xE9diaires pour combler le \xAB d\xE9sert \xBB entre les badges du d\xE9but et la ma\xEEtrise compl\xE8te d'une table : \xAB Premi\xE8re case r\xE9v\xE9l\xE9e \xBB (1\xE8re multiplication pass\xE9e en bo\xEEte 4) et \xAB Premi\xE8re multiplication ma\xEEtris\xE9e \xBB (1\xE8re en bo\xEEte 5). Ils se d\xE9bloquent au moment o\xF9 l'image myst\xE8re change visiblement de finesse pour la premi\xE8re fois."]},{date:"2026-05-01",items:["Les badges \xAB Table de N \xBB tombent plus vite quand l'enfant a r\xE9ussi le test de placement : un fait inf\xE9r\xE9 \xE0 partir d'une r\xE9ponse rapide d\xE9marre d\xE9sormais en bo\xEEte 3 (et plus en bo\xEEte 2), reconnaissant la ma\xEEtrise d\xE9j\xE0 d\xE9montr\xE9e."]},{date:"2026-04-30",items:["Les deux derniers faits (8\xD79 et 9\xD79) sont d\xE9sormais bien introduits en fin de parcours, m\xEAme si certains autres faits sont retomb\xE9s en bo\xEEte 1.","La pill \xAB s\xE9rie \xBB de l'\xE9cran d'accueil affiche maintenant l'\xE9tat r\xE9el : si plusieurs jours sans s\xE9ance compl\xE8te, elle passe \xE0 \xAB On s'y remet ? \xBB au lieu de garder fig\xE9e la derni\xE8re valeur."]},{date:"2026-04-29",items:["Page \xAB Nouveaut\xE9s \xBB accessible depuis l'espace parent (la voici).","Le test de placement reconna\xEEt maintenant les faits faciles d\xE9j\xE0 connus \xE0 partir des plus durs : 2\xD72, 2\xD73, etc. ne restent plus comme \xAB non introduits \xBB quand l'enfant a r\xE9ussi des multiplications difficiles.","Si le mode vocal est activ\xE9, la permission micro est demand\xE9e d\xE8s le premier tap apr\xE8s le lancement de l'app, plut\xF4t qu'en pleine s\xE9ance."]},{date:"2026-04-28",items:["Le splash screen iOS n'affiche plus un carr\xE9 indigo aux bords droits \u2014 un m\xE9daillon circulaire \xE0 la place.","La s\xE9ance redevient disponible automatiquement apr\xE8s minuit sans avoir \xE0 fermer l'app.","Le feedback de fin de question peut maintenant scroller en mode paysage."]},{date:"2026-04-27",items:["Possibilit\xE9 de basculer entre clavier et micro pendant une s\xE9ance, sans quitter.","Modale d\xE9taill\xE9e au tap sur la pill de streak (jours d'affil\xE9e).","Modale d\xE9taill\xE9e pour les badges, avec conditions et progression.","L'\xE9cran ne s'\xE9teint plus pendant une s\xE9ance.","Animation des r\xE8gles d'introduction (\xD710) cal\xE9e sur la voix."]},{date:"2026-04-25",items:["Splash screens iOS pour iPhone et iPad.","Landing marketing pour faciliter l'installation PWA depuis Safari.","Page Confidentialit\xE9 accessible depuis l'espace parent.","Sous-titres explicatifs et liens \xAB ? \xBB vers le guide dans le dashboard parent."]}];export{e as CHANGELOG};

